final:
module binary_counter (
    input clk,
    input enable,
    input reset_n,
    output [3:0] count
);
    reg [3:0] invalid_count;

    always @(posedge clk or negedge reset_n) begin
        if (!reset_n)
            invalid_count <= 4'b0000;
        else if (enable)
            invalid_count <= invalid_count + 1;
    end

    assign count = invalid_count;

endmodule
